import hmac
import hashlib
import base64
import struct
import time
import qrcode
import io
import secrets
from typing import Optional, Tuple


class TOTPAuthenticator:
    def __init__(self, time_step: int = 30, digits: int = 6, algorithm: str = 'sha1'):
        self.time_step = time_step
        self.digits = digits
        self.algorithm = algorithm.lower()
        self.hash_algorithms = {
            'sha1': hashlib.sha1,
            'sha256': hashlib.sha256,
            'sha512': hashlib.sha512
        }
        
    def generate_secret(self, length: int = 32) -> str:
        random_bytes = secrets.token_bytes(length)
        secret = base64.b32encode(random_bytes).decode('utf-8')
        return secret.rstrip('=')
    
    def _get_counter(self, timestamp: Optional[int] = None) -> int:
        if timestamp is None:
            timestamp = int(time.time())
        return timestamp // self.time_step
    
    def _generate_hotp(self, secret: str, counter: int) -> str:
        secret_bytes = base64.b32decode(secret + '=' * ((8 - len(secret) % 8) % 8))
        counter_bytes = struct.pack('>Q', counter)
        
        hash_func = self.hash_algorithms.get(self.algorithm, hashlib.sha1)
        hmac_hash = hmac.new(secret_bytes, counter_bytes, hash_func).digest()
        
        offset = hmac_hash[-1] & 0x0F
        truncated_hash = struct.unpack('>I', hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
        
        otp = truncated_hash % (10 ** self.digits)
        return str(otp).zfill(self.digits)
    
    def generate_totp(self, secret: str, timestamp: Optional[int] = None) -> str:
        counter = self._get_counter(timestamp)
        return self._generate_hotp(secret, counter)
    
    def verify_totp(self, secret: str, token: str, timestamp: Optional[int] = None, 
                    window: int = 1) -> bool:
        if timestamp is None:
            timestamp = int(time.time())
        
        current_counter = self._get_counter(timestamp)
        
        for i in range(-window, window + 1):
            counter = current_counter + i
            expected_token = self._generate_hotp(secret, counter)
            if hmac.compare_digest(expected_token, token):
                return True
        
        return False
    
    def get_provisioning_uri(self, secret: str, account_name: str, 
                            issuer_name: str) -> str:
        params = {
            'secret': secret,
            'issuer': issuer_name,
            'algorithm': self.algorithm.upper(),
            'digits': self.digits,
            'period': self.time_step
        }
        
        param_string = '&'.join([f'{k}={v}' for k, v in params.items()])
        uri = f'otpauth://totp/{issuer_name}:{account_name}?{param_string}'
        return uri
    
    def generate_qr_code(self, secret: str, account_name: str, 
                        issuer_name: str) -> bytes:
        uri = self.get_provisioning_uri(secret, account_name, issuer_name)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        img_bytes = io.BytesIO()
        img.save(img_bytes, format='PNG')
        return img_bytes.getvalue()
    
    def save_qr_code(self, secret: str, account_name: str, 
                    issuer_name: str, filename: str) -> None:
        qr_bytes = self.generate_qr_code(secret, account_name, issuer_name)
        with open(filename, 'wb') as f:
            f.write(qr_bytes)


class UserTOTPManager:
    def __init__(self, authenticator: Optional[TOTPAuthenticator] = None):
        self.authenticator = authenticator or TOTPAuthenticator()
        self.users = {}
    
    def register_user(self, username: str, email: str) -> Tuple[str, str]:
        secret = self.authenticator.generate_secret()
        
        self.users[username] = {
            'email': email,
            'secret': secret,
            'enabled': False,
            'backup_codes': self._generate_backup_codes()
        }
        
        return secret, self.authenticator.get_provisioning_uri(
            secret, email, 'MyApp'
        )
    
    def _generate_backup_codes(self, count: int = 10) -> list:
        codes = []
        for _ in range(count):
            code = secrets.token_hex(4).upper()
            codes.append(code)
        return codes
    
    def enable_totp(self, username: str, token: str) -> bool:
        if username not in self.users:
            return False
        
        user = self.users[username]
        if self.authenticator.verify_totp(user['secret'], token):
            user['enabled'] = True
            return True
        return False
    
    def verify_user_token(self, username: str, token: str, 
                         allow_backup: bool = True) -> bool:
        if username not in self.users:
            return False
        
        user = self.users[username]
        if not user['enabled']:
            return False
        
        if self.authenticator.verify_totp(user['secret'], token):
            return True
        
        if allow_backup and token.upper() in user['backup_codes']:
            user['backup_codes'].remove(token.upper())
            return True
        
        return False
    
    def get_user_secret(self, username: str) -> Optional[str]:
        if username in self.users:
            return self.users[username]['secret']
        return None
    
    def get_backup_codes(self, username: str) -> Optional[list]:
        if username in self.users:
            return self.users[username]['backup_codes'].copy()
        return None
    
    def regenerate_backup_codes(self, username: str) -> Optional[list]:
        if username not in self.users:
            return None
        
        new_codes = self._generate_backup_codes()
        self.users[username]['backup_codes'] = new_codes
        return new_codes.copy()
    
    def disable_totp(self, username: str) -> bool:
        if username not in self.users:
            return False
        
        self.users[username]['enabled'] = False
        return True
    
    def remove_user(self, username: str) -> bool:
        if username in self.users:
            del self.users[username]
            return True
        return False


